namespace sv_12b069105ff0482ab6fc87765e5701b9.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly object _lock = new();

    public event Action? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get { lock (_lock) { return _notifications.ToList(); } }
    }

    public int GetUnreadCount()
    {
        lock (_lock) { return _notifications.Count(n => !n.IsRead); }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Insert(0, new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace sv_12b069105ff0482ab6fc87765e5701b9.Services;

public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private static readonly string[] Titles =
    [
        "CPU spike detected",
        "Deployment completed",
        "Disk space low",
        "New user signup",
        "Payment failed",
        "Service restarted",
        "Memory usage high",
        "Backup completed"
    ];

    private static readonly string[] Messages =
    [
        "Server node-3 reported elevated CPU usage for 30s.",
        "Version 2.4.1 deployed to production cluster.",
        "Volume /data is at 92% capacity.",
        "A new user registered via OAuth.",
        "Payment gateway returned timeout for order #8821.",
        "Service auth-api was restarted by watchdog.",
        "Container mem-limit reached 85% threshold.",
        "Nightly backup to S3 completed successfully."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return;
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _cts = null;
        _timer = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        var rng = Random.Shared;
        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var idx = rng.Next(Titles.Length);
            var severity = (Severity)rng.Next(3);
            _hub.AddNotification(Titles[idx], Messages[idx], severity);
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

