@page "/notifications"
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable
@using sv_12b069105ff0482ab6fc87765e5701b9.Services

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<button class="btn btn-outline-primary mb-3" @onclick="Hub.MarkAllRead">
    Mark All Read
</button>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _notifications.GroupBy(n => n.Severity).OrderByDescending(g => g.Key))
    {
        <h4 class="mt-3">
            <span class="badge @GetSeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>
        <ul class="list-group mb-2">
            @foreach (var n in group.OrderByDescending(x => x.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-bold")">
                    <div class="ms-2 me-auto">
                        <div>@n.Title</div>
                        <small class="text-muted">@n.Message</small>
                        <br />
                        <small class="text-secondary">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => Hub.MarkAsRead(n.Id)">Mark Read</button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Hub.DismissNotification(n.Id)">Dismiss</button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IReadOnlyList<Notification> _notifications = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        _notifications = Hub.Notifications;
        _handler = () => InvokeAsync(() =>
        {
            _notifications = Hub.Notifications;
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private static string GetSeverityBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

